#include "kernel_operator.h"
#include "ca6k00322_custom_tiling.h"

constexpr int32_t BUFFER_NUM = 1;

class KernelCa6k00322Custom {
public:
    __aicore__ inline KernelCa6k00322Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t tileLength,
                                int32_t groups, uint32_t channels,
                                uint32_t height, uint32_t width)
    {
        totalLen_ = totalLength;
        tileLen_ = tileLength;
        groups_ = groups;
        channels_ = channels;
        height_ = height;
        width_ = width;
        spatialStride_ = height_ * width_;
        perBatch_ = channels_ * spatialStride_;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpBuf_, 1, sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || tileLen_ == 0) return;

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        const uint32_t strideElems = blockNum * tileLen_;
        uint32_t base = blockIdx * tileLen_;
        if (base >= totalLen_) return;

        while (true) {
            uint32_t curLen = totalLen_ - base;
            if (curLen > tileLen_) curLen = tileLen_;
            if (curLen == 0) break;

            AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
            AscendC::LocalTensor<float> tmp = tmpBuf_.Get<float>();

            for (uint32_t i = 0; i < curLen; i++) {
                uint32_t outIdx = base + i;
                uint32_t n = outIdx / perBatch_;
                uint32_t rem = outIdx % perBatch_;
                uint32_t c = rem / spatialStride_;
                uint32_t rem2 = rem % spatialStride_;
                uint32_t h = rem2 / width_;
                uint32_t w = rem2 % width_;

                uint32_t channelsPerGroup = channels_ / groups_;
                uint32_t cSrc = (c % groups_) * channelsPerGroup + (c / groups_);
                uint32_t srcIdx = n * perBatch_ + cSrc * spatialStride_ + h * width_ + w;

                AscendC::DataCopy(tmp, xGm_[srcIdx], 1);
                yLocal.SetValue(i, tmp.GetValue(0));
            }

            outQueueY_.EnQue<float>(yLocal);

            AscendC::LocalTensor<float> yLocalOut = outQueueY_.DeQue<float>();
            AscendC::DataCopy(yGm_[base], yLocalOut, curLen);
            outQueueY_.FreeTensor(yLocalOut);

            base += strideElems;
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> tmpBuf_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t tileLen_ {0};
    int32_t groups_ {1};
    uint32_t channels_ {0};
    uint32_t height_ {0};
    uint32_t width_ {0};
    uint32_t spatialStride_ {0};
    uint32_t perBatch_ {0};
};

